var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"레이첼! 레이첼!","JPN":"レイチェル！　レイチェル！","ENG":"Rachel! Rachel!","TWN":"瑞秋！瑞秋！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"왜요, 원장님. 해 달라는 빨래 청소 화단에 물 주기까지 다 끝냈잖아요.","JPN":"何ですか、院長？　洗濯に掃除に花壇の水やりまで、頼まれてたのは全部やりましたよ？","ENG":"What now, headmaster? I've done the laundry, swept the floors, and even finished watering the plants like you asked me to.","TWN":"怎麼了，院長？你叫我洗衣服、打掃、澆花，我都做完啦？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"저 이제 진짜 그림 그리러 가야 되거든요? 침식체 할애비가 와도 지금은 못 막거든요?","JPN":"そろそろ本当に絵を描きに行かないとマズいんですよ！　侵食体が来たって今のアタシは止められません！","ENG":"I really gotta go do art stuff now, okay? Not even a C.O. and his uncle could stop me now.","TWN":"我要去畫畫了啦！現在就算是侵蝕體爺爺來，也阻止不了我的！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"지금 네 낙서가 문제냐. 밖이나 좀 내다 봐 봐.","JPN":"今落書きしている場合じゃないんだ、外を見てみろ。","ENG":"Your graffiti can wait. Take a look outside.","TWN":"現在重點是畫畫嗎？你看看外面！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"밖에 왜요? 또 갱단끼리 싸움 났어요?","JPN":"外？　またギャング同士のトラブルですか？","ENG":"Why? Is there another gang war?","TWN":"外面怎樣？又有幫派鬧事喔？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>두려워하지 마십시오, 여러분. 저희는 제프티 바이오테크에서 파견한 의료 봉사단입니다.</color>","JPN":"<color=#ffd34c>皆様、恐れることはありません。我々はジェフティ・バイオテックから派遣された医療奉仕団です。</color>","ENG":"<color=#ffd34c>Do not be afraid, everyone. We are a medical relief team dispatched from Jehuty Biotech.</color>","TWN":"<color=#ffd34c>大家請不要害怕，我們是傑夫堤生物科技派來的義診團隊。</color>"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>지금 광장에서 무상 진료를 시행하고 있습니다. 의약품도 무상으로 지급하고 있사오니…….</color>","JPN":"<color=#ffd34c>現在、広場で無料診療を行っております。医薬品も無料配布しておりますので……</color>","ENG":"<color=#ffd34c>We are currently providing free medical examinations at the plaza. We're also offering medical supplies free of charge…</color>","TWN":"<color=#ffd34c>現在正在廣場提供義診，藥物也免費提供……</color>"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"애들 옷 입히게 좀 도와 줘라. 오늘은 공짜 건강검진 받는 날이야.","JPN":"子どもたちの着替えを手伝ってくれ。今日は無料健診の日だ。","ENG":"Help me get the children dressed. We can have them get a free physical.","TWN":"替我幫孩子們穿好衣服，今天是免費體檢的日子。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"안 돼요. 오늘은 호라이즌이 처음으로 혼자 아르바이트 하는 날이라고요.","JPN":"ダメですよ。今日はホライズンが初めてアルバイトをする日なんです。","ENG":"No. Today's Horizon's first day at her new job.","TWN":"不行，今天是地平線她第一次自己打工。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"서프라이즈 선물 준비하려면 시간 없어요.","JPN":"サプライズプレゼントを用意するには時間がないんですよ。","ENG":"I don't have enough time to prepare a surprise gift for her as it is.","TWN":"我還要去準備驚喜送給她。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"그 녀석 머리에 접시 달고 다니는 것 빼면 항상 쌩쌩하더구만. 뭘 그리 야단이야.","JPN":"そんなことよりこっちの方が大事だろう！　あいつは少し変わっているけど、いつも元気じゃないか。","ENG":"She seems to be doing just fine on her own, save for those weird plates on her head. What's with all the fuss about?","TWN":"排除她頭上掛著盤子，其他我看都很正常啊，哪需要奔波這些？！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아휴, 진짜! 그런 심보로 사니까 독신이지!","JPN":"もう！　冷たいんだから！　そんなんだからいまだに独身なんですよ！","ENG":"Ugh! No wonder you're forever alone, you old grouch!","TWN":"哀哀～真是的！原來院長都是這種想法，難怪你還是單身狗！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"잠깐, 나 혼자서 애들 다 어떻게 챙기라고! 레이첼!","JPN":"待ってくれ、私一人では無理なんだよ！　おい、レイチェル！","ENG":"Wait! How am I supposed to take care of all the kids by myself? Rachel!","TWN":"你等等，我一個人怎麼照顧這群小孩啦！瑞秋！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"어디 보자, 스프레이가…… 녹색 한 통, 남색 한 통……","JPN":"どれどれ、スプレーは……緑一本と、紺が一本……","ENG":"Let's see… Spray cans… I've got green, indigo…","TWN":"我看看喔，噴漆……一桶綠色，一桶藍色……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"응? 레이첼 아냐?","JPN":"あれ、レイチェルじゃないか？","ENG":"Huh? Rachel?","TWN":"嗯？那不是瑞秋嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"흐야악?!","JPN":"ひゃあ！？","ENG":"Eeek!","TWN":"哇啊？！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"뭐야, 오빠! 깜짝 놀랐네! 덩치도 크면서 기척은 내고 다닐 것이지!","JPN":"なんだ、ビックリしたじゃない！　そんなデカい体がいきなり出てきたら驚くって！","ENG":"Ugh, come on! You scared me! How does someone your size move so quietly?!","TWN":"你幹嘛啦！嚇我一大跳！這麼大一尊，是不會出點聲音喔！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"아이고. 이거 죄송합니다. 미래의 아티스트를 놀라게 해 버렸네.","JPN":"これはこれは、申し訳ありませんね。将来のアーティストさんに大変失礼いたしました。","ENG":"Oh. My apologies. I didn't mean to startle the future master artist.","TWN":"哎呀，真是對不起，嚇到我們未來的大藝術家。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"그런데 왜 여기 있어? 진료 받으러 안 가?","JPN":"ていうかなんでここにいるんだ？　健診に行かないのか？","ENG":"What are you still doing here anyway? You're not going to go get an examination?","TWN":"不過你怎麼在這裡，你不去找醫生義診嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"진료는 무슨. 난 어릴 때부터 통뼈라서 걱정없네요.","JPN":"健診？　子どもの頃からずっと元気だし、そんなの要らないよ。","ENG":"Oh, please. I've always been as healthy as a horse since I was little.","TWN":"有什麼好義診的，我從小就壯得跟頭牛一樣，沒事啦！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그보다 오빠, 침식지대에 갔던 사람들 소식 뭐 안 들어왔어?","JPN":"それより、お兄ちゃん。侵食地帯に行った人たちから連絡とかなかったの？","ENG":"By the way, have you heard anything back from the folks who went to the Corrupted Area?","TWN":"我倒想問一下，那些去侵蝕地區的人都沒消息嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"안 그래도 방금 막 연락이 왔지. 예언회 놈들이 또 습격해 왔다나 봐.","JPN":"ちょうどさっき連絡がきたぞ。預言会の連中にまた襲われたらしい。","ENG":"As a matter of fact, I just did. Sounds like the MPS attacked again.","TWN":"剛才正好收到消息，預言會那些傢伙似乎又發動攻擊。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"예언회……?","JPN":"預言会……？","ENG":"MPS?","TWN":"預言會……？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"와, 그 거적대기 걸치고 다니는 아저씨들 엄청 질척질척하네.","JPN":"はあ、あのぼろぼろのおじさんたち、本当に懲りないんだね。","ENG":"Dang, those rag-wearing weirdos never give up, do they?","TWN":"哇，那些穿著布袋的大叔還真難纏！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"그래도 한동안은 잠잠할 거야.","JPN":"まあ、しばらくは大人しくするだろう。","ENG":"But things should stay quiet for a while.","TWN":"不過他們暫時應該不會再有行動。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"통신으로 들었는데 그놈들 두목이 갑자기 날아온 트럭에 깔렸다더라고.","JPN":"通信の内容だと、奴らのボスがいきなり飛んできたトラックの下敷きになったらしい。","ENG":"I heard over the comms that their boss got smashed by a truck that flew out of nowhere.","TWN":"剛才通話得知，他們的主教被天外飛來的卡車給壓住了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"트럭에? 아니, 그게 왜 날아와?","JPN":"トラックに！？　飛んできた？","ENG":"A truck? Wait, did you say it flew?","TWN":"被卡車壓住？不過，卡車怎麼會飛？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"통신 보낸 친구 말로는 근처에 있던 침식체 짓 아니냐고 하던데……","JPN":"聞いた話だと、近くの侵食体がやったんじゃないかと……","ENG":"The guy who radioed me said it might be from a C.O. nearby…","TWN":"傳消息來的人說，懷疑是附近的侵蝕體做的……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"난 민병대가 도와줬다고 생각한다.","JPN":"でも個人的には民兵隊が助けてくれたんだと思うよ。","ENG":"Personally, I'd like to think it was the Militia.","TWN":"但我個人認為是民兵隊幫的忙。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"민병대? 악질 카운터한테 대신 복수해 준다는 사람들 말이야?","JPN":"民兵隊？　悪質なカウンターに代わりに復讐してくれる人たちのこと？","ENG":"The Militia? You mean those guys who take revenge on evil Counters?","TWN":"民兵隊？就是那些向惡劣制裁者報仇的人嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"오빠도 참. 그런 자살지망생들이 요즘 세상에 어디 있어.","JPN":"まさか。このご時世、あんな自殺行為をする人たちがいるわけないでしょ？","ENG":"Come on, man. You know no one's that suicidal anymore.","TWN":"你想太多，現在哪有這種自願去送死的人？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"하하. 동감이야. 그냥 그런 사람들도 있으면 좋겠다는 얘기지.","JPN":"ハハ、それは同感だ。まあ、そんな人たちがいればいいなってことで。","ENG":"Haha. I know. Just wishful thinking.","TWN":"哈哈，同感。應該是我希望有那樣的人吧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"에휴. 이 머릿속이 꽃밭인 오빠들. 여자친구는 어떻게 사귀려나 몰라.","JPN":"もう、頭の中がお花畑なんだから。そんなに甘っちょろいと彼女なんて一生できないよ。","ENG":"*Sigh...* Y'all may be older but you're still like little boys in your head. Good luck trying to find a girlfriend.","TWN":"哎呀，你們這些腦袋不清楚的人，真不知道要怎麼交女朋友。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"마침 잘됐네. 호라이즌 오면 4번가 사무실로 오라고 전해 줘.","JPN":"あ、でもちょうどよかった。ホライズンが来たら4番地の事務所に来てほしいって伝えてね。","ENG":"Oh, that reminds me. Tell Horizon to come to the office on 4th Avenue when she comes back.","TWN":"對了，地平線回來的話，跟她說到第四大道的辦公室找我。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"응? 같이 진료받으러 가는 게 아니라?","JPN":"え？　あの子と健診にいくんじゃないのか？","ENG":"Huh? You're not going to go get examined?","TWN":"嗯？不是一起去找醫生義診喔？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그건 나중에. 지금은 서프라이즈 선물 준비해야 하거든.","JPN":"それは後でいいよ。今はサプライズプレゼントを用意しないとなの。","ENG":"That can wait. I've got a surprise present to prepare.","TWN":"義診以後再說啦，現在要先準備驚喜禮物。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"선물……? 네가 돈이 어디 있다고?","JPN":"プレゼント……？　お前に金なんてないだろ？","ENG":"A present? But aren't you broke?","TWN":"禮物……？你哪來的錢？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"선물을 꼭 사서 해 주란 법이 있나. 정성이 중요한 거야, 정성.","JPN":"プレゼントっていうのは必ず買う必要はないでしょ？　気持ちが大事なの、キ・モ・チ。","ENG":"You don't necessarily have to buy stuff to give a gift. It's all about the heart.","TWN":"誰說禮物一定要花錢買？重點是心意好嗎？心意！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"……모처럼 좋은 그림 소재를 찾았거든.","JPN":"……ちょうどいい素材を見つけたの。","ENG":"…I found the perfect subject for my art, you see.","TWN":"……我好不容易才找到很棒的素材。"},"stage":{"bg":"HORIZON_01_B","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그 고집불통도 이번에는 감동해서 눈물을 펑펑 흘릴걸.","JPN":"あの頑固な子でも、今回ばかりは感動して涙をぽろぽろ流すと思うよ。","ENG":"Even that stubborn fool will be moved to tears this time.","TWN":"再怎麼鐵石心腸，這次也一定會感動到痛哭流涕的！"},"stage":{"bg":"HORIZON_01_B","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"하하. 하긴 네 실력은 우리가 보장하긴 하지.","JPN":"ハハ。まあお前も実力だけはプロレベルだからな。","ENG":"Haha. Well, I can certainly vouch for your artsy skills.","TWN":"哈哈，也是，你的實力我們可是有目共睹。"},"stage":{"bg":"HORIZON_01_B","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"얘기 전해 둘게. 그 애가 깜짝 놀랄 만큼 멋진 작품 그려 봐.","JPN":"伝えておくよ。あの子がビックリするくらい素敵なものを描いてみな。","ENG":"I'll pass the word. I hope your masterpiece will be so impressive it'll knock those plates right off her head.","TWN":"我會轉告她的。你就畫一幅會讓她大吃一驚的作品吧！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"당연하지. 내 작품은 항상 최고로 멋지니까.","JPN":"当然よ！　アタシの作品は常に素晴らしいんだからね。","ENG":"Of course. My work is always amazing.","TWN":"那當然囉，我的作品每次都是最棒的！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"잊지 마, 호라이즌.","JPN":"忘れるな……ホライズン。","ENG":"Don't forget, Horizon.","TWN":"記住，地平線，"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"우리가……. 그리고 내가 너를 만들었던 건.","JPN":"私たちが……そして私があなたを作ったのは……","ENG":"We… I made you because…","TWN":"是我們…是我創造你的……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"……어?","JPN":"……え？","ENG":"…Huh?","TWN":"……嗯？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MOB_HORIZON_NULL_NULL","text":{"KOREA":"손 들어. 머리에 바람 구멍 나기 전에.","JPN":"手を上げろ。頭に風穴を空けられたくなかったらな。","ENG":"Put your hands in the air. If you don't want a hole in your skull.","TWN":"把手舉起來，否則我會在你頭上開個洞。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOB_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L20_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"자, 잠깐만요. 뭔가 오해하신 것 같은데 전 그냥……","JPN":"ま、待ってください。何か誤解しているみたいですけどアタシはただ……","ENG":"H-hang on. There must be some misunderstanding. I'm just a…","TWN":"等…等一下。是不是有什麼誤會，我只是…"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MBOSS_HORIZON_NULL_NULL","text":{"KOREA":"대장님, 민간인 같습니다. 어떡할까요.","JPN":"隊長、民間人のようです。どうしますか？","ENG":"Sir, she seems to be just a civilian. What should we do?","TWN":"隊長，好像只是個平民，怎麼辦？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MBOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"아니. 기웃거리는 꼴을 봐선 타깃과 관련되어 있을 수도 있다.","JPN":"いや、この辺をウロチョロしているということはターゲットに関わっている可能性もある。","ENG":"No. The way she's been prowling around suggests that she may have something to do with the target.","TWN":"不，看她一副賊頭賊腦的，可能與我們的目標有關。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MBOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"상대에 대해 알아낼 정보가 있을지도 몰라. 심문해.","JPN":"ターゲットの情報を持っているかもしれない。尋問しろ。","ENG":"She might have some information about the target. Interrogate her.","TWN":"查問她，或許可以得到目標的資訊。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MBOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MBOSS_HORIZON_NULL_NULL","text":{"KOREA":"모른다고 하면 어떡하죠?","JPN":"知らないと言われたらどうします？","ENG":"What if she says she doesn't know?","TWN":"萬一她說不知道呢？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MBOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"그걸 말이라고 묻나?","JPN":"それを聞くのか？","ENG":"Was that a genuine question?","TWN":"你是認真的嗎？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MBOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"당연히 고분고분 불 때까지 손봐 줘야지.","JPN":"大人しく吐き出すまで痛めつけてやれ。","ENG":"Then \\"coax\\" her until she fesses up.","TWN":"當然是打到她說為止！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"사람들을 지키기 위해서였어.","JPN":"人々を守るためだった。","ENG":"I just wanted to protect them.","TWN":"為的是要守護人們。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};